decimal runningTotal = 0;
decimal runningTotalCloseF = 0;
decimal runningTotalOpenC = 0;
decimal runningTotalCloseC = 0;
decimal runningTotalTotalEggs = 0;

private void xrTableCell35_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     // Helper function for safe parsing
    decimal GetFieldValue(string fieldName)
    {
        object value = GetCurrentColumnValue(fieldName);
        if (value != null && !string.IsNullOrEmpty(value.ToString()))
        {
            if (decimal.TryParse(value.ToString(), out decimal result))
                return result;
        }
        return 0;
    }

    // Get report parameters - replace with your actual parameter names
    // You need to access them from your report's Parameters collection
    DateTime dateFrom = (DateTime)Report.GetParameterValue("DateFrom");
    DateTime dateTo = (DateTime)Report.GetParameterValue("DateTo");

    // Calculate SameDate
    decimal sameDate = (dateFrom.Date == dateTo.Date) ? 1 : 0;

    // Calculate OpenF
    decimal openF = GetFieldValue("OpenFHTEggsF") + GetFieldValue("OpenHTEggsF");

    // Calculate result
    decimal result = 0;

    if (sameDate == 1)
    {
        // Add to running total
        runningTotal += openF;
        result = runningTotal;
    }
    else
    {
        result = 0;
    }

    // Assign result to cell
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N0");
}

