private void xrTableCell46_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // Helper function for safe parsing
    decimal GetFieldValue(string fieldName)
    {
        object value = GetCurrentColumnValue(fieldName);
        if (value != null && !string.IsNullOrEmpty(value.ToString()))
        {
            if (decimal.TryParse(value.ToString(), out decimal result))
                return result;
        }
        return 0;
    }

    // Get report parameters
    DateTime dateFrom = (DateTime)Report.GetParameterValue("DateFrom");
    DateTime dateTo = (DateTime)Report.GetParameterValue("DateTo");

    // Calculate SameDate
    decimal sameDate = (dateFrom.Date == dateTo.Date) ? 1 : 0;

    // Calculate TotalFHE
    decimal totalFHE = GetFieldValue("CloseFHTEggsC") + GetFieldValue("CloseFHTEggsF");

    // Calculate TotalHE
    decimal totalHE = GetFieldValue("CloseHTEggsC") + GetFieldValue("CloseHTEggsF");

    // Calculate TotalEggs
    decimal totalEggs = totalFHE + totalHE;

    // Calculate result
    decimal result = 0;

    if (sameDate == 1)
    {
        // Add to running total
        runningTotalTotalEggs += totalEggs;
        result = runningTotalTotalEggs;
    }
    else
    {
        result = 0;
    }

    // Assign result to cell
    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("N0");
}
